// Apply rotation (angle in radians)
t = cc.affineTransformRotate(t, Math.PI / 4); // 45 degrees

// Concatenate two transforms
const t1 = cc.affineTransformMake(1, 0, 0, 1, 50, 0);  // translate
const t2 = cc.affineTransformScale(cc.affineTransformMake(1, 0, 0, 1, 0, 0), 2, 2); // scale
const combined = cc.affineTransformConcat(t1, t2);

// Invert a transform
const inv = cc.affineTransformInvert(t);

// Apply transform to a point
const original = cc.p(10, 20);
const transformed = cc.pointApplyAffineTransform(original, t);

// Apply transform to a rect
