function checkRectCollision(
    nodeA: cc.Node,
    nodeB: cc.Node
): boolean {
    const boxA: cc.Rect = nodeA.getBoundingBox();
    const boxB: cc.Rect = nodeB.getBoundingBox();
    return cc.rectOverlapsRect(boxA, boxB);
}

// More detailed collision info
function getCollisionInfo(
    nodeA: cc.Node,
    nodeB: cc.Node
): { collides: boolean; overlap: cc.Rect | null } {
    const boxA = nodeA.getBoundingBox();
    const boxB = nodeB.getBoundingBox();

    if (!cc.rectOverlapsRect(boxA, boxB)) {
        return { collides: false, overlap: null };
    }

    return {
        collides: true,
        overlap: cc.rectIntersection(boxA, boxB)
    };
}

// Usage:
const player = new cc.Sprite('res/player.png');
const enemy = new cc.Sprite('res/enemy.png');

if (checkRectCollision(player, enemy)) {
    cc.log('Collision detected!');
}

const info = getCollisionInfo(player, enemy);
if (info.collides && info.overlap) {
    cc.log('Overlap area:', info.overlap.width, 'x', info.overlap.height);
}
