class CircularMotion extends cc.Node {
    private _center: cc.Point;
    private _radius: number;
    private _angularSpeed: number; // radians per second
    private _currentAngle: number = 0;
    private _sprite: cc.Sprite;

    constructor(
        spritePath: string,
        center: cc.Point,
        radius: number,
        degreesPerSecond: number
    ) {
        super();
        this._center = center;
        this._radius = radius;
        this._angularSpeed = degreesPerSecond * cc.RAD;

        this._sprite = new cc.Sprite(spritePath);
        this.addChild(this._sprite);
        this.scheduleUpdate();
    }

    update(dt: number): void {
        this._currentAngle += this._angularSpeed * dt;

        // Calculate position on circle
        const basePoint = cc.p(this._center.x + this._radius, this._center.y);
        const pos = cc.pRotateByAngle(basePoint, this._center, this._currentAngle);
        this.setPosition(pos);
    }
}

