interface CollisionResult {
    overlaps: boolean;
    overlapX: number;
    overlapY: number;
    pushDirection: cc.Point;
}

function calculateOverlap(
    rectA: cc.Rect,
    rectB: cc.Rect
): CollisionResult {
    if (!cc.rectOverlapsRect(rectA, rectB)) {
        return { overlaps: false, overlapX: 0, overlapY: 0, pushDirection: cc.p(0, 0) };
    }

    const inter = cc.rectIntersection(rectA, rectB);

    // Determine push direction based on centers
    const centerA = cc.p(rectA.x + rectA.width / 2, rectA.y + rectA.height / 2);
    const centerB = cc.p(rectB.x + rectB.width / 2, rectB.y + rectB.height / 2);
    const diff = cc.pSub(centerA, centerB);

    let pushDir: cc.Point;
    if (inter.width < inter.height) {
        pushDir = cc.p(diff.x > 0 ? 1 : -1, 0);
    } else {
        pushDir = cc.p(0, diff.y > 0 ? 1 : -1);
    }

    return {
        overlaps: true,
        overlapX: inter.width,
        overlapY: inter.height,
        pushDirection: pushDir
    };
}

// Usage:
const result = calculateOverlap(player.getBoundingBox(), wall.getBoundingBox());
if (result.overlaps) {
    const minOverlap = Math.min(result.overlapX, result.overlapY);
    const push = cc.pMult(result.pushDirection, minOverlap);
    const newPos = cc.pAdd(player.getPosition(), push);
    player.setPosition(newPos);
}
```

