function arrangeInCircle(
    nodes: cc.Node[],
    center: cc.Point,
    radius: number
): void {
    const count = nodes.length;
    if (count === 0) return;

    const angleStep = (Math.PI * 2) / count;
    const startAngle = Math.PI / 2; // start at top (12 o'clock)

    for (let i = 0; i < count; i++) {
        const angle = startAngle + angleStep * i;
        const pos = cc.p(
            center.x + radius * Math.cos(angle),
            center.y + radius * Math.sin(angle)
        );
        nodes[i].setPosition(pos);
    }
}

// Usage:
const items: cc.Node[] = [];
for (let i = 0; i < 8; i++) {
    const sprite = new cc.Sprite('res/icon.png');
    this.addChild(sprite);
    items.push(sprite);
}

arrangeInCircle(items, cc.p(240, 160), 100);
```

Each node is placed at equal angular intervals. The `startAngle` of `PI/2` places the first node at the top; adjust to `0` for the rightmost position.

