function snapToGrid(
    position: cc.Point,
    cellSize: cc.Size
): cc.Point {
    const gridX = Math.round(position.x / cellSize.width);
    const gridY = Math.round(position.y / cellSize.height);
    return cc.p(
        gridX * cellSize.width,
        gridY * cellSize.height
    );
}

// Variant: snap to cell center (offset by half cell)
function snapToGridCenter(
    position: cc.Point,
    cellSize: cc.Size
): cc.Point {
    const gridX = Math.floor(position.x / cellSize.width);
    const gridY = Math.floor(position.y / cellSize.height);
    return cc.p(
        gridX * cellSize.width + cellSize.width / 2,
        gridY * cellSize.height + cellSize.height / 2
