Review this code that implements a bounding box union:

```typescript
function getCombinedBounds(nodes: cc.Node[]): cc.Rect {
    let combined = nodes[0].getBoundingBox();
    for (let i = 1; i < nodes.length; i++) {
        combined = cc.rectUnion(combined, nodes[i].getBoundingBox());
    }
    return combined;
