const pos: cc.Point = node.getPosition();

// Dimensions — use cc.Size
node.setContentSize(cc.size(200, 100));
const winSize: cc.Size = cc.director.getWinSize();

// They are NOT interchangeable even though both have 2 numbers:
const p = cc.p(100, 200);     // p.x, p.y
const s = cc.size(100, 200);  // s.width, s.height
```

