interface VisionCone {
    readonly position: cc.Point;
    readonly direction: cc.Point;  // unit vector
    readonly range: number;
    readonly halfAngle: number;    // radians
}

function isInVisionCone(cone: VisionCone, target: cc.Point): boolean {
    // Distance check
    const distSQ = cc.pDistanceSQ(cone.position, target);
    if (distSQ > cone.range * cone.range) return false;

    // Angle check
    const toTarget = cc.pNormalize(cc.pSub(target, cone.position));
    const angle = cc.pAngle(cone.direction, toTarget);
    return angle <= cone.halfAngle;
}

