output:
```typescript
function reflect(
    velocity: cc.Point,
    normal: cc.Point
): cc.Point {
    // Reflection formula: v - 2 * dot(v, n) * n
    const n = cc.pNormalize(normal);
    const dot = cc.pDot(velocity, n);
    return cc.pSub(velocity, cc.pMult(n, 2 * dot));
}

// Usage: ball bouncing off walls
class BouncingBall extends cc.Node {
    private _velocity: cc.Point = cc.p(200, 150);
    private _sprite: cc.Sprite;

    constructor() {
        super();
        this._sprite = new cc.Sprite('res/ball.png');
        this.addChild(this._sprite);
        this.scheduleUpdate();
    }

    update(dt: number): void {
        const pos = this.getPosition();
        let newPos = cc.pAdd(pos, cc.pMult(this._velocity, dt));
        const winSize = cc.director.getWinSize();

        // Bounce off right/left walls
        if (newPos.x > winSize.width || newPos.x < 0) {
            this._velocity = reflect(this._velocity, cc.p(1, 0));
            newPos = cc.pAdd(pos, cc.pMult(this._velocity, dt));
        }
        // Bounce off top/bottom walls
        if (newPos.y > winSize.height || newPos.y < 0) {
            this._velocity = reflect(this._velocity, cc.p(0, 1));
            newPos = cc.pAdd(pos, cc.pMult(this._velocity, dt));
        }

        this.setPosition(newPos);
    }
}
```

