Signature: `cc.rectContainsRect(rect1: cc.Rect, rect2: cc.Rect): boolean`

Returns `true` only if `rect1` completely contains `rect2` — all four corners of `rect2` must be inside `rect1`. This is stricter than `cc.rectOverlapsRect` which only requires partial overlap.

```typescript
interface AABB {
    readonly center: cc.Point;
    readonly halfSize: cc.Size;
}

function nodeToAABB(node: cc.Node): AABB {
    const box = node.getBoundingBox();
    return {
        center: cc.p(box.x + box.width / 2, box.y + box.height / 2),
        halfSize: cc.size(box.width / 2, box.height / 2)
    };
}

function aabbToRect(aabb: AABB): cc.Rect {
    return cc.rect(
        aabb.center.x - aabb.halfSize.width,
        aabb.center.y - aabb.halfSize.height,
        aabb.halfSize.width * 2,
        aabb.halfSize.height * 2
    );
}

function aabbOverlaps(a: AABB, b: AABB): boolean {
    return cc.rectOverlapsRect(aabbToRect(a), aabbToRect(b));
}

function aabbSeparation(a: AABB, b: AABB): cc.Point {
    const diff = cc.pSub(a.center, b.center);
    const overlapX = a.halfSize.width + b.halfSize.width - Math.abs(diff.x);
    const overlapY = a.halfSize.height + b.halfSize.height - Math.abs(diff.y);

    if (overlapX <= 0 || overlapY <= 0) return cc.p(0, 0);

    if (overlapX < overlapY) {
        return cc.p(diff.x > 0 ? overlapX : -overlapX, 0);
    }
    return cc.p(0, diff.y > 0 ? overlapY : -overlapY);
}

// Usage:
const playerAABB = nodeToAABB(playerSprite);
const wallAABB = nodeToAABB(wallSprite);

if (aabbOverlaps(playerAABB, wallAABB)) {
    const sep = aabbSeparation(playerAABB, wallAABB);
    const pos = playerSprite.getPosition();
    playerSprite.setPosition(cc.pAdd(pos, sep));
}
```

